import Box from '@mui/material/Box'
import Typography from '@mui/material/Typography'
import { Icon } from '@iconify/react'
import SectionHeading from '../ui/SectionHeading'
import { ONE_PLATFORM } from '../data/landing.data'
import { SECTION_IDS } from '@/utils/constant'

function TruckVisual() {
  return (
    <Box
      sx={{
        position: 'relative',
        height: 200,
        borderRadius: 'var(--radius-md)',
        backgroundColor: 'var(--surface-page)',
        overflow: 'hidden',
        display: 'flex',
        alignItems: 'flex-end',
        justifyContent: 'flex-end',
      }}
    >
      <Box
        sx={{
          position: 'absolute',
          right: 24,
          top: 32,
          width: 110,
          height: 110,
          opacity: 0.16,
          color: 'var(--brand-primary)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
        }}
      >
        <Icon icon='mdi:cube-outline' fontSize={110} />
      </Box>
      <Box sx={{ color: 'var(--brand-primary)', display: 'flex', alignItems: 'flex-end' }}>
        <Icon icon='mdi:truck' fontSize={140} />
      </Box>
    </Box>
  )
}

function InsightsVisual() {
  return (
    <Box sx={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 1, mt: 'auto' }}>
      {[
        { label: 'Delivery Rate', value: '91.4%', delta: '+0.8pp' },
        { label: 'First Attempt Delivery', value: '84.2%', delta: '+1.2pp' },
        { label: 'Avg Transit Time', value: '3.4 days', delta: '+0.2' },
      ].map((m) => (
        <Box
          key={m.label}
          sx={{
            backgroundColor: '#FFFFFF',
            border: '1px solid var(--border-subtle)',
            borderRadius: 'var(--radius-md)',
            p: 1.25,
            display: 'flex',
            flexDirection: 'column',
            gap: 0.5,
          }}
        >
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5, color: 'var(--text-subtitle)' }}>
            <Box
              sx={{
                width: 14,
                height: 14,
                borderRadius: '4px',
                backgroundColor: 'var(--color-yellow-opacity-main)',
                display: 'inline-flex',
                alignItems: 'center',
                justifyContent: 'center',
              }}
            >
              <Icon icon='mdi:chart-line-variant' fontSize={9} color='#B5870A' />
            </Box>
            <Typography sx={{ fontSize: '0.5625rem', fontWeight: 600 }}>{m.label}</Typography>
          </Box>
          <Typography sx={{ fontSize: '0.9375rem', fontWeight: 800, color: 'var(--text-strong)' }}>{m.value}</Typography>
          <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <Typography sx={{ fontSize: '0.5rem', color: 'var(--text-subtitle)' }}>vs Last Period</Typography>
            <Typography sx={{ fontSize: '0.5625rem', fontWeight: 700, color: 'var(--color-success-dark)' }}>
              {m.delta}
            </Typography>
          </Box>
        </Box>
      ))}
    </Box>
  )
}

export default function OnePlatformSection() {
  return (
    <Box id={SECTION_IDS.CAPABILITIES} className='landing-section' sx={{ backgroundColor: 'var(--surface-page)' }}>
      <Box className='landing-container'>
        <SectionHeading
          eyebrow={ONE_PLATFORM.eyebrow}
          title={ONE_PLATFORM.titleLeading}
          accent={ONE_PLATFORM.titleAccent}
          subtitle={ONE_PLATFORM.subtitle}
          size='md'
        />

        <Box
          sx={{
            mt: { xs: 5, md: 7 },
            display: 'grid',
            gridTemplateColumns: { xs: '1fr', md: 'repeat(2, 1fr)' },
            gap: 2.5,
          }}
        >
          {ONE_PLATFORM.topCards.map((card, i) => (
            <Box
              key={card.title}
              sx={{
                backgroundColor: 'var(--surface-muted)',
                border: '1px solid var(--border-subtle)',
                borderRadius: 'var(--radius-lg)',
                p: { xs: 2.5, md: 3 },
                display: 'flex',
                flexDirection: 'column',
                gap: 2,
                minHeight: 320,
              }}
            >
              <Typography variant='Heading/H4-Bold' sx={{ color: 'var(--text-strong)' }}>
                {card.title}
              </Typography>
              <Typography variant='Body/S-Regular' sx={{ color: 'var(--text-secondary)', lineHeight: 1.6 }}>
                {card.description}
              </Typography>
              <Box sx={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
                {i === 0 ? <TruckVisual /> : <InsightsVisual />}
              </Box>
            </Box>
          ))}
        </Box>

        <Box
          sx={{
            mt: 2.5,
            display: 'grid',
            gridTemplateColumns: { xs: '1fr', sm: 'repeat(3, 1fr)' },
            gap: 2.5,
          }}
        >
          {ONE_PLATFORM.listCards.map((card) => (
            <Box
              key={card.title}
              sx={{
                backgroundColor: 'var(--surface-muted)',
                border: '1px solid var(--border-subtle)',
                borderRadius: 'var(--radius-lg)',
                p: { xs: 2.5, md: 3 },
                display: 'flex',
                flexDirection: 'column',
                gap: 1.5,
              }}
            >
              <Typography variant='Heading/H5-Bold' sx={{ color: 'var(--text-strong)' }}>
                {card.title}
              </Typography>
              <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1 }}>
                {card.items.map((item) => (
                  <Box key={item} sx={{ display: 'flex', alignItems: 'center', gap: 1, color: 'var(--text-secondary)' }}>
                    <Icon icon='mdi:check' fontSize={14} color='#FBC942' />
                    <Typography variant='Body/S-Regular'>{item}</Typography>
                  </Box>
                ))}
              </Box>
            </Box>
          ))}
        </Box>
      </Box>
    </Box>
  )
}
